record_types.code:
type Controller is
   record
      Name : Text;
      Id   : Text;
      Skin : controllers.Skin;
   end record;

type Item is
   record
      Contents : access Controller_array;
   end record;

type Joints is
   record
      Inputs : Inputs_view;
   end record;

type Skin is
   record
      main_Source       :        Text;
      bind_shape_Matrix :        float_Array (1 .. 16);
      Sources           : access library.Sources;
      Joints            :        controllers.Joints;
      vertex_weights    :        controllers.vertex_Weights;
   end record;

type vertex_Weights is
   record
      Count   : Natural;
      Inputs  : Inputs_view;
      v_Count : int_Array_view;
      v       : int_Array_view;
   end record;
